function isPalRange(str, left, right) {
  while (left < right) {
    if (str[left] !== str[right]) return false;
    left++;
    right--;
  }
  return true;
}

function almostPalindrome(s) {
  const cleaned = (s || "")
    .replace(/[^a-zA-Z0-9]/g, "")
    .toLowerCase();

  let left = 0;
  let right = cleaned.length - 1;

  while (left < right) {
    if (cleaned[left] === cleaned[right]) {
      left++;
      right--;
      continue;
    }

    return (
      isPalRange(cleaned, left + 1, right) ||
      isPalRange(cleaned, left, right - 1)
    );
  }

  return true;
}

using System;
using System.Text;

public static class Solution
{
    private static bool IsPalRange(string str, int left, int right)
    {
        while (left < right)
        {
            if (str[left] != str[right]) return false;
            left++;
            right--;
        }
        return true;
    }

    public static bool AlmostPalindrome(string s)
    {
        var input = s ?? string.Empty;
        var sb = new StringBuilder(input.Length);

        foreach (char ch in input)
        {
            if (char.IsLetterOrDigit(ch))
            {
                sb.Append(char.ToLowerInvariant(ch));
            }
        }

        string cleaned = sb.ToString();
        int left = 0;
        int right = cleaned.Length - 1;

        while (left < right)
        {
            if (cleaned[left] == cleaned[right])
            {
                left++;
                right--;
                continue;
            }

            return IsPalRange(cleaned, left + 1, right) || IsPalRange(cleaned, left, right - 1);
        }

        return true;
    }
}
